<!DOCTYPE html><html lang="en"><head><meta charset="UTF-8"><title>Print {{ $registration->registration_number }}</title><style>body{font-family:Arial,sans-serif;color:#111}.wrap{max-width:760px;margin:0 auto}h1{color:#153764}table{width:100%;border-collapse:collapse}td{padding:8px;border-bottom:1px solid #ddd}td:first-child{font-weight:bold;width:34%}@media print{button{display:none}}</style></head><body><div class="wrap"><button onclick="window.print()">Print</button><h1>AP Registration {{ $registration->registration_number }}</h1><table><tr><td>Student</td><td>{{ $registration->student_full_name }}</td></tr><tr><td>Status</td><td>{{ $registration->status }}</td></tr><tr><td>Email</td><td>{{ $registration->student_email }}</td></tr><tr><td>School</td><td>{{ $registration->school_name }}</td></tr><tr><td>Exams</td><td>{{ $registration->exams->pluck('name')->join(', ') }}</td></tr><tr><td>Total</td><td>NT$ {{ number_format($registration->total_fee) }}</td></tr></table></div></body></html>
